arguments.new_str:
using Microsoft.EntityFrameworkCore;

// ---------------------------------------------------------------------------
// EF Core 8 → 9 Cosmos DB Breaking Changes (with 500K existing documents)
// ---------------------------------------------------------------------------
//
// BREAKING CHANGE 1 – Discriminator property renamed
//   EF Core 9 writes "$type" instead of "Discriminator".
//   Existing docs have: { "Discriminator": "Product", … }
//   Without the fix below, EF 9 queries filter on "$type" → 0 results.
//   Direct SQL queries (`c.Discriminator`) would also return nothing for
//   new documents, and EF LINQ queries would miss all old documents.
//   FIX: HasDiscriminator<string>("Discriminator") restores the old name.
//
// BREAKING CHANGE 2 – id value no longer contains the entity-type prefix
//   EF Core 8 stored the Cosmos `id` as "Product|123" (via a shadow
//   property named "__id").  EF Core 9 maps the CLR key directly to `id`,
//   producing just "123".  Existing 500K documents still have "Product|123"
//   and will NOT be found by EF Core 9 unless we preserve the old format.
//   FIX: We introduce an explicit `CosmosId` property that carries the
//   legacy format, mark it as the Cosmos identity, and keep the integer
//   `Id` as a separate stored property.
//
// BREAKING CHANGE 3 – Synchronous I/O throws at runtime
//   The Cosmos provider now throws InvalidOperationException for sync calls
//   like ToList(), First(), SaveChanges(), etc.
//   FIX: Use async equivalents (ToListAsync, SaveChangesAsync, …).
//
// BREAKING CHANGE 4 – HasIndex is not supported on Cosmos
//   In EF 8 this was silently ignored.  EF 9 may warn or throw during
//   model validation.  Cosmos indexes must be managed through the Azure
//   portal, ARM/Bicep templates, or the Cosmos SDK – not EF Core.
//   FIX: Remove the HasIndex call.
// ---------------------------------------------------------------------------

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // (CHANGE 1) Keep the legacy discriminator property name so
            // existing documents and raw SQL queries still work.
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // (CHANGE 2) Preserve the EF Core 8 "EntityType|Key" id format.
            // CosmosId is the Cosmos document identity; the integer Id is
            // stored alongside it under the JSON property "Id".
            b.HasKey(p => p.CosmosId);
            b.Property(p => p.CosmosId)
             .ToJsonProperty("id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();

            b.Property(p => p.Id)
             .ToJsonProperty("Id");

            // (CHANGE 4) Removed – was: b.HasIndex(p => p.Sku);
            // Cosmos indexes must be configured outside EF Core.
        });
    }
}

// Entity updated with an explicit Cosmos id property for backward compat.
class Product
{
    /// <summary>Cosmos document "id".  Legacy format: "Product|{Id}".</summary>
    public string CosmosId { get; set; } = null!;
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

// Value generator that reproduces the EF Core 8 "EntityType|Key" id format.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    protected override string NextValue(EntityEntry entry)
    {
        var id = entry.Property("Id").CurrentValue;
        return $"Product|{id}";
    }
}

